# Category: ssrf

local http = require "resty.http"

-- Create a new HTTP client
local httpc = http.new()

-- Set the timeout for the client
httpc:set_timeout(1000) -- 1 second

-- Define the proxy handler
function proxy_handler(ngx)
    local url = ngx.var.arg_url
    if not url then
        return ngx.exit(400)
    end

    -- Fetch content from the target URL
    local res, err = httpc:request_uri(url)
    if not res then
        return ngx.exit(500)
    end

    -- Forward the response to the client
    ngx.print(res.body)
end